        long v = (long) edge[1];
        long s = (long) edge[2];
        long must = (long) edge[3];

        if (must == 1) {
            mustEdges.add(new long[]{u, v, s});
        } else {
            optionalEdges.add(new long[]{u, v, s});
        }
    }

    // Check if the must-include edges form a connected graph
    // Use Union-Find (Disjoint Set Union) for this
    UnionFind dsu = new UnionFind((int) n);
    for (long[] edge : mustEdges) {
