    // We can use a modified Kruskal's algorithm with a priority queue
    // Sort optional edges by their strength (we can upgrade them)
    Collections.sort(optionalEdges, (a, b) -> Long.compare(a[2], b[2]));

    // Use a priority queue to keep track of the optional edges we can upgrade
    PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(b[2], a[2]));

    // Add all optional edges to the priority queue
    for (long[] edge : optionalEdges) {
        pq.add(edge);
    }

    // Use Union-Find again to check connectivity
    dsu = new UnionFind((int) n);

    // Add all must-include edges
    for (long[] edge : mustEdges) {
        dsu.union((int) edge[0], (int) edge[1]);
    }

    // Try to upgrade optional edges to maximize the minimum strength
    long maxStability = 0;
    long upgradesUsed = 0;

    while (!pq.isEmpty()) {
        long[] edge = pq.poll();
        long u = (long) edge[0];
        long v = (long) edge[1];
        long s = (long) edge[2];

        // Check if we can upgrade this edge
        if (upgradesUsed < k) {
            // Upgrade the edge
            s *= 2;
            upgradesUsed++;
