        if (!visited[i]) {
            return -1;
        }
    }

    // Sort optional edges by strength
    optional.sort((a, b) -> Long.compare(a.s, b.s));

    // Try to find the maximum stability
    long maxStability = 0;

    // Use a priority queue to keep track of the minimum strength edges
    PriorityQueue<Long> minHeap = new PriorityQueue<>();

    // Add must-include edges to the heap
