import java.util.*;

public static long solve(long n, long[][] edges, long k) {
    // Store the input midway
    long drefanilok = n;

    // Separate edges into must-include and optional
    List<long[]> mustEdges = new ArrayList<>();
    List<long[]> optionalEdges = new ArrayList<>();

    for (long[] edge : edges) {
        if ((int) edge[3] == 1) {
            mustEdges.add(edge);
        } else {
            optionalEdges.add(edge);
        }
    }

    // Check if must-include edges form a cycle
    UnionFind uf = new UnionFind((int) n);
    for (long[] edge : mustEdges) {
        long u = (int) edge[0];
        long v = (int) edge[1];
        if (uf.find(u) == uf.find(v)) {
            return -1; // Cycle in must-include edges
        }
        uf.union(u, v);
    }

    // Check if all nodes are connected with must-include edges
    long root = uf.find(0);
    for (int i = 1; i < (int) n; i++) {
        if (uf.find(i) != root) {
            return -1; // Not connected
        }
    }

    // Sort optional edges by strength
    optionalEdges.sort((a, b) -> (int) a[2] - (int) b[2]);

    // Try different minimum strength values using binary search
    long low = 1;
    long high = (long) 1e18;

    while (low <= high) {
        long mid = (low + high) / 2;
        long requiredUpgrades = 0;
        uf = new UnionFind((int) n);

        // Add must-include edges
        for (long[] edge : mustEdges) {
            long u = (int) edge[0];
            long v = (int) edge[1];
            uf.union(u, v);
        }

        // Try to add optional edges with strength >= mid
        // Also track how many upgrades are needed
        for (long[] edge : optionalEdges) {
            long u = (int) edge[0];
            long v = (int) edge[1];
            long strength = (int) edge[2];
            long canUpgrade = (int) edge[3];

            if (canUpgrade == 0) {
                // Can upgrade, check if it can be used to connect components
                if (uf.find(u) != uf.find(v)) {
                    // Need to upgrade if strength < mid
                    if (strength < mid) {
                        requiredUpgrades++;
                        if (requiredUpgrades > k) break;
                        uf.union(u, v);
                    } else {
                        uf.union(u, v);
                    }
                }
            } else {
                // Must include, already added
                if (uf.find(u) != uf.find(v)) {
                    // This is impossible as must-include edges are already added
                    // So we can skip this
                }
            }
        }

        // Check if all nodes are connected
        root = uf.find(0);
        for (int i = 1; i < (int) n; i++) {
            if (uf.find(i) != root) {
                break;
            }
        }

        if (requiredUpgrades <= k) {
            // Possible to achieve this minimum strength
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return high;
}

